import jwt
from datetime import datetime, timedelta

def generate_jwt(user_id, role, secret_key):
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': datetime.utcnow() + timedelta(days=1)  # Token expires in one day
    }
    token = jwt.encode(payload, secret_key, algorithm='HS256')
    return token

